import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"量子断虹","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/量子断虹.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/量子断虹.md"}'),p={name:"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/量子断虹.md"};function d(l,a,_,i,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"量子断虹",tabindex:"-1"},[s("量子断虹 "),e("a",{class:"header-anchor",href:"#量子断虹","aria-label":'Permalink to "量子断虹"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),o('<h1 id="量子断虹-1" tabindex="-1">量子断虹 <a class="header-anchor" href="#量子断虹-1" aria-label="Permalink to &quot;量子断虹&quot;">​</a></h1><p>量子断虹<br> D+750<br> 科技本质<br> 武器类别：唐刀<br> 专业：刀<br> 武器伤害：6L<br> 体积：3<br> 特性：轻灵，破甲1<br> 伤害类型：物理-挥砍</p><p>为了快速斩开新时代罪犯所安装的防御用义体而使用的依据唐刀为基础改造的新时代武器。</p><p>你可以花招动作启动量子断虹的切割功能，在接下来三轮内使用该武器的攻击额外具有等同于你敏捷属性一半的【破甲】（向上取整）。</p><p>量子断虹-镜<br> C+1000<br> 科技本质<br> 需在量子断虹的基础上逐级购买，使量子断虹的武器伤害提升8L，并更名为【量子断虹-镜】。</p><p>那高速振动的刀刃，与水天无镜无二。</p><p>由于切割功能获得了提升，原本的效果改为：以一个花招动作启动量子断虹的切割功能，在接下来三轮内使用该武器的攻击额外具有等同于你敏捷属性的【破甲】（向上取整），若你在计算防御后破甲仍有剩余，可将至多敏捷属性点破甲转为攻击上的增强加值。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=r(p,[["render",d]]);export{f as __pageData,m as default};
